export default {
    ambientLight: {
        intensity: 1.0,
        color: "#1c1e21"
    },
    pointLight: {
        position: [1, 1, 1],
        intensity: 1.5,
        color: "#ffffff"
    },
    printables: {
        float: {
            speed: 2.5,
            rotationIntensity: 1,
            floatIntensity: 1,
            floatingRange: [-0.1, 0.1]
        },
        scale: [1, 1, 1],
        position: [0, 0, 0],
        rotation: [0, 0, 0],
        color: "#eb6f40"
    }
};
